  def fa_icon(name, class_name: "h-4 w-4", title: nil)
    view_box, path = FONT_AWESOME_PATHS.fetch(name)
    options = {
      class: class_name,
      viewBox: view_box,
      fill: "currentColor",
      role: title.present? ? "img" : nil,
      "aria-hidden": title.present? ? nil : "true"
    }.compact

    tag.svg(**options) do
      safe_join([
        (tag.title(title) if title.present?),
        tag.path(d: path)
      ].compact)
    end
  end
